#include <iostream>
#include <string>
using namespace std;

int minSwitches(string L1, string L2, int n) {
    int dp[2][n];
    dp[0][0] = (L1[0] == '#') ? -1 : 0;
    dp[1][0] = (L2[0] == '#') ? -1 : 0;
    for (int i = 1; i < n; i++) {
        if (L1[i] == '#') {
            dp[0][i] = -1;
        } else if (L2[i] == '#') {
            dp[0][i] = (dp[1][i-1] != -1) ? dp[1][i-1] + 1 : -1;
        } else {
            if (dp[0][i-1] != -1 && dp[1][i-1] != -1) {
                dp[0][i] = (dp[0][i-1] < dp[1][i-1] + 1) ? dp[0][i-1] : dp[1][i-1] + 1;
            } else if (dp[0][i-1] != -1) {
                dp[0][i] = dp[0][i-1];
            } else if (dp[1][i-1] != -1) {
                dp[0][i] = dp[1][i-1] + 1;
            } else {
                dp[0][i] = -1;
            }
        }
        if (L2[i] == '#') {
            dp[1][i] = -1;
        } else if (L1[i] == '#') {
            dp[1][i] = (dp[0][i-1] != -1) ? dp[0][i-1] + 1 : -1;
        } else {
            if (dp[1][i-1] != -1 && dp[0][i-1] != -1) {
                dp[1][i] = (dp[1][i-1] < dp[0][i-1] + 1) ? dp[1][i-1] : dp[0][i-1] + 1;
            } else if (dp[1][i-1] != -1) {
                dp[1][i] = dp[1][i-1];
            } else if (dp[0][i-1] != -1) {
                dp[1][i] = dp[0][i-1] + 1;
            } else {
                dp[1][i] = -1;
            }
        }
    }
    if (dp[0][n-1] == -1 && dp[1][n-1] == -1) {
        return -1;
    } else if (dp[0][n-1] == -1) {
        return dp[1][n-1];
    } else if (dp[1][n-1] == -1) {
        return dp[0][n-1];
    } else {
        return (dp[0][n-1] < dp[1][n-1]) ? dp[0][n-1] : dp[1][n-1];
    }
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        string L1, L2;
        cin >> L1;
        cin >> L2;
        int n = L1.length();
        int min = minSwitches(L1, L2, n);
        if (min == -1) {
            cout << "No" << endl;
        } else {
            cout << "Yes" << endl;
            cout << min << endl;
        }
    }
    return 0;
}
